export function getTourById(id) {
  return tours.find(t => t.id === id);
}

export function getTourBySlug(slug) {
  return tours.find(t => t.slug === slug);
}

export function getToursByDestination(destinationId) {
  return tours.filter(t => t.destinationId === destinationId && t.active);
}

export function getToursByTier(tier) {
  return tours.filter(t => t.tier === tier && t.active);
}

export function getToursByCategory(category) {
  return tours.filter(t => t.category === category && t.active);
}

export function getDestinations() {
  const seen = new Set();
  return tours
    .filter(t => t.active)
    .filter(t => { if(seen.has(t.destinationId)) return false; seen.add(t.destinationId); return true; })
    .map(t => ({ id: t.destinationId, slug: t.destinationSlug, name: t.destination, region: t.region, country: t.country, category: t.category }));
}

export function getRelatedTours(tour, limit = 3) {
  return tours
    .filter(t => t.active && t.slug !== tour.slug && t.category === tour.category)
    .slice(0, limit);
}
